#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

import argparse
import json
import re
from pathlib import Path

from plan_context_common import (
    PHASE_FILES,
    append_jsonl,
    context_dir_for_plan,
    get_current_plan,
    now_iso,
    rel_posix,
    resolve_plan_path,
    validate_plan_location,
)
from spec_common import (
    load_ignored_dir_names,
    repo_root,
    relevant_child_directories,
    relevant_markdown_files,
    summary_from_markdown,
)


def tokenize(value: str) -> list[str]:
    return [token for token in re.split(r'[^a-z0-9]+', value.lower()) if token]


def mode_for_candidate(path: Path, phase: str, score: float) -> str:
    if path.name == 'index.md':
        return 'summary'
    if phase in {'implement', 'review'} and score >= 6:
        return 'full'
    return 'summary'


def score_candidate(path: Path, rel: str, summary: str, tokens: list[str], phase: str) -> tuple[float, list[str]]:
    score = 0.0
    reasons: list[str] = []
    filename = path.name.lower()
    rel_lower = rel.lower()
    summary_lower = summary.lower()
    is_index = path.name == 'index.md'

    for token in tokens:
        if token in filename:
            score += 4.0
            reasons.append(f'filename matched {token}')
        elif token in rel_lower:
            score += 3.0
            reasons.append(f'path matched {token}')

        if token in summary_lower:
            score += 2.0
            reasons.append(f'summary matched {token}')

    if phase == 'plan' and is_index:
        score += 0.5
    if phase in {'implement', 'review'} and not is_index:
        score += 0.5

    return score, reasons


def collect_candidates(spec_root: Path, ignored_dir_names: set[str]) -> list[Path]:
    candidates: list[Path] = []

    root_index = spec_root / 'index.md'
    if root_index.is_file():
        candidates.append(root_index)

    for directory in relevant_child_directories(spec_root, ignored_dir_names):
        index_path = directory / 'index.md'
        if index_path.is_file():
            candidates.append(index_path)

    for path in sorted(spec_root.rglob('*.md')):
        if not path.is_file():
            continue
        if any(part.startswith('.') for part in path.relative_to(spec_root).parts):
            continue
        if any(part in ignored_dir_names for part in path.relative_to(spec_root).parts[:-1]):
            continue
        if path not in candidates:
            candidates.append(path)

    return candidates


def select_candidates(spec_root: Path, hint: str, phase: str, limit: int, categories: list[str]) -> list[dict]:
    ignored_dir_names = load_ignored_dir_names(spec_root)
    tokens = tokenize(hint)
    category_set = {item.lower() for item in categories}
    rows: list[dict] = []

    for path in collect_candidates(spec_root, ignored_dir_names):
        rel = path.relative_to(spec_root).as_posix()
        rel_for_output = f'.superpowers/spec/{rel}'
        parts = path.relative_to(spec_root).parts
        if category_set and (not parts or parts[0].lower() not in category_set):
            continue

        summary = summary_from_markdown(path)
        score, reasons = score_candidate(path, rel, summary, tokens, phase)
        if score <= 0:
            continue

        rows.append({
            'path': rel_for_output,
            'score': round(score, 2),
            'mode': mode_for_candidate(path, phase, score),
            'reason': '; '.join(dict.fromkeys(reasons)) or 'matched hint tokens',
            'summary': summary,
            'isIndex': path.name == 'index.md',
        })

    rows.sort(key=lambda item: (-item['score'], item['path']))
    return rows[:limit]


def render_text(hint: str, phase: str, candidates: list[dict], wrote_count: int = 0) -> str:
    lines = [
        f'Hint: {hint}',
        f'Phase: {phase}',
        '',
        'Recommended spec candidates:',
    ]

    if not candidates:
        lines.append('- No matching spec candidates found')
        return '\n'.join(lines)

    for index, item in enumerate(candidates, start=1):
        lines.append(f'{index}. {item["path"]}')
        lines.append(f'   - score: {item["score"]}')
        lines.append(f'   - mode: {item["mode"]}')
        lines.append(f'   - reason: {item["reason"]}')
        if item.get('summary'):
            lines.append(f'   - summary: {item["summary"]}')

    if wrote_count:
        lines.extend(['', f'Wrote {wrote_count} candidates to sidecar'])

    return '\n'.join(lines)


def load_target_plan(root: Path, plan_arg: str | None) -> Path:
    if plan_arg:
        plan_path = resolve_plan_path(root, plan_arg)
        validate_plan_location(root, plan_path)
        if not plan_path.is_file():
            raise ValueError(f'Plan file not found: {rel_posix(root, plan_path)}')
        return plan_path

    plan_path = get_current_plan(root)
    if plan_path is None:
        raise ValueError('No current plan set; pass --plan or run set-current first')
    return plan_path


def write_candidates_to_sidecar(root: Path, plan_path: Path, phase: str, candidates: list[dict], default_mode: str) -> int:
    context_dir = context_dir_for_plan(plan_path)
    if not context_dir.is_dir():
        raise ValueError(f'Context sidecar not initialized: {rel_posix(root, context_dir)}')

    phase_file = context_dir / PHASE_FILES[phase]
    timestamp = now_iso()

    for item in candidates:
        record = {
            'type': 'spec',
            'path': item['path'],
            'reason': item['reason'],
            'phase': phase,
            'mode': item.get('mode') or default_mode,
            'selectedBy': 'selector',
            'createdAt': timestamp,
            'updatedAt': timestamp,
        }
        append_jsonl(phase_file, record)

    return len(candidates)


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser()
    parser.add_argument('hint')
    parser.add_argument('--phase', choices=('plan', 'implement', 'review'), default='plan')
    parser.add_argument('--category', action='append', default=[])
    parser.add_argument('--limit', type=int, default=5)
    parser.add_argument('--json', action='store_true')
    parser.add_argument('--write-sidecar', action='store_true')
    parser.add_argument('--plan')
    parser.add_argument('--default-mode', choices=('summary', 'full'), default='summary')
    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()

    root = repo_root(Path.cwd())
    spec_root = root / '.superpowers' / 'spec'
    if not spec_root.is_dir():
        raise SystemExit('No .superpowers/spec directory found')

    candidates = select_candidates(
        spec_root=spec_root,
        hint=args.hint,
        phase=args.phase,
        limit=max(args.limit, 1),
        categories=args.category,
    )

    wrote_count = 0
    if args.write_sidecar:
        plan_path = load_target_plan(root, args.plan)
        wrote_count = write_candidates_to_sidecar(
            root=root,
            plan_path=plan_path,
            phase=args.phase,
            candidates=candidates,
            default_mode=args.default_mode,
        )

    if args.json:
        print(json.dumps({
            'hint': args.hint,
            'phase': args.phase,
            'candidates': candidates,
            'wroteCount': wrote_count,
        }, ensure_ascii=False, indent=2))
    else:
        print(render_text(args.hint, args.phase, candidates, wrote_count=wrote_count))

    return 0


if __name__ == '__main__':
    raise SystemExit(main())
